def saml_metadata(request: HttpRequest) -> HttpResponse:
    entity_id = _get_setting("SAML_ENTITY_ID", None) or request.build_absolute_uri("/")
    acs_url = _get_setting("SAML_ACS_URL", None) or request.build_absolute_uri(reverse("saml_acs"))
    cert = _get_setting("SAML_SP_X509_CERT", "")

    cert_clean = "".join([line.strip() for line in cert.splitlines() if "BEGIN" not in line and "END" not in line]).strip()

    nsmd = "urn:oasis:names:tc:SAML:2.0:metadata"
    md = etree.Element("{%s}EntityDescriptor" % nsmd, nsmap={None: nsmd})
    md.set("entityID", entity_id)

    sp = etree.SubElement(md, "{%s}SPSSODescriptor" % nsmd)
    sp.set("protocolSupportEnumeration", "urn:oasis:names:tc:SAML:2.0:protocol")
    sp.set("AuthnRequestsSigned", "false")
    sp.set("WantAssertionsSigned", "true")

    if cert_clean:
        keydesc = etree.SubElement(sp, "{%s}KeyDescriptor" % nsmd)
        keydesc.set("use", "signing")
        keyinfo = etree.SubElement(keydesc, "{%s}KeyInfo" % DSIG_NS, nsmap={"ds": DSIG_NS})
        x509data = etree.SubElement(keyinfo, "{%s}X509Data" % DSIG_NS)
        x509cert = etree.SubElement(x509data, "{%s}X509Certificate" % DSIG_NS)
        x509cert.text = cert_clean

    acs = etree.SubElement(sp, "{%s}AssertionConsumerService" % nsmd)
    acs.set("Binding", "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST")
    acs.set("Location", acs_url)
    acs.set("index", "1")
    acs.set("isDefault", "true")

    xml = etree.tostring(md, xml_declaration=True, encoding="UTF-8", pretty_print=True)
    return HttpResponse(xml, content_type="application/samlmetadata+xml")


